:root {
  --primary: #1e2a5e;
  --secondary: #ff6b4a;
  --secondary-dark: #e65c2f;
  --accent: #d4a017;
  --bg-soft: #f9f9fb;
  --text: #333333;
  --text-muted: #6b7280;
}

html {
  scroll-behavior: smooth;
}

body {
  font-family: 'Noto Sans JP', 'Inter', 'Helvetica Neue', sans-serif;
  color: var(--text);
  overflow-x: hidden;
}

/* Matrix / tech background */
.matrix-bg {
  background-image:
    linear-gradient(rgba(30, 42, 94, 0.03) 1px, transparent 1px),
    linear-gradient(90deg, rgba(30, 42, 94, 0.03) 1px, transparent 1px);
  background-size: 24px 24px;
}

.hero-gradient {
  background: linear-gradient(135deg, #f5f7fa 0%, #e4e8f0 50%, #ffffff 100%);
}

.section-gradient {
  background: linear-gradient(180deg, #ffffff 0%, #f9f9fb 100%);
}

/* Logo glitch */
@keyframes glitch {
  0%, 100% { transform: translate(0); }
  20% { transform: translate(-2px, 1px); }
  40% { transform: translate(2px, -1px); }
  60% { transform: translate(-1px, -1px); }
  80% { transform: translate(1px, 1px); }
}

.logo-glitch:hover,
.logo-glitch.glitch-once {
  animation: glitch 0.4s ease;
}

/* Fade-in on scroll */
.reveal {
  opacity: 0;
  transform: translateY(20px);
  transition: opacity 0.7s ease, transform 0.7s ease;
}

.reveal.is-visible {
  opacity: 1;
  transform: translateY(0);
}

.reveal-stagger > * {
  opacity: 0;
  transform: translateY(20px);
  transition: opacity 0.5s ease, transform 0.5s ease;
}

.reveal-stagger.is-visible > *:nth-child(1) { transition-delay: 0.05s; }
.reveal-stagger.is-visible > *:nth-child(2) { transition-delay: 0.1s; }
.reveal-stagger.is-visible > *:nth-child(3) { transition-delay: 0.15s; }
.reveal-stagger.is-visible > *:nth-child(4) { transition-delay: 0.2s; }
.reveal-stagger.is-visible > *:nth-child(5) { transition-delay: 0.25s; }
.reveal-stagger.is-visible > *:nth-child(6) { transition-delay: 0.3s; }

.reveal-stagger.is-visible > * {
  opacity: 1;
  transform: translateY(0);
}

/* Hero underline draw */
.hero-underline {
  position: relative;
  display: inline-block;
}

.hero-underline::after {
  content: '';
  position: absolute;
  left: 0;
  bottom: -4px;
  width: 0;
  height: 3px;
  background: var(--secondary);
  transition: width 1s ease 0.5s;
}

.hero-underline.is-visible::after {
  width: 100%;
}

/* Animated buttons */
.btn-primary {
  position: relative;
  display: inline-flex;
  align-items: center;
  justify-content: center;
  padding: 0.875rem 2rem;
  font-weight: 700;
  color: #fff;
  background: var(--secondary);
  border: 2px solid var(--secondary);
  border-radius: 9999px;
  overflow: hidden;
  transition: transform 0.25s ease, box-shadow 0.25s ease;
  z-index: 1;
}

.btn-primary::before {
  content: '';
  position: absolute;
  inset: 0;
  background: linear-gradient(90deg, var(--secondary-dark), #ff8f75, var(--secondary));
  transform: translateX(-100%);
  transition: transform 0.4s ease;
  z-index: -1;
}

.btn-primary::after {
  content: '';
  position: absolute;
  inset: -2px;
  border-radius: 9999px;
  border: 2px solid transparent;
  background: linear-gradient(90deg, var(--accent), var(--secondary)) border-box;
  -webkit-mask: linear-gradient(#fff 0 0) padding-box, linear-gradient(#fff 0 0);
  mask: linear-gradient(#fff 0 0) padding-box, linear-gradient(#fff 0 0);
  -webkit-mask-composite: xor;
  mask-composite: exclude;
  opacity: 0;
  transition: opacity 0.3s ease;
}

.btn-primary:hover {
  transform: scale(1.05);
  box-shadow: 0 12px 28px rgba(255, 107, 74, 0.35);
}

.btn-primary:hover::before {
  transform: translateX(0);
}

.btn-primary:hover::after {
  opacity: 1;
}

.btn-outline {
  position: relative;
  display: inline-flex;
  align-items: center;
  justify-content: center;
  padding: 0.875rem 2rem;
  font-weight: 700;
  color: var(--primary);
  background: transparent;
  border: 2px solid var(--primary);
  border-radius: 9999px;
  overflow: hidden;
  transition: transform 0.25s ease, color 0.3s ease, box-shadow 0.25s ease;
}

.btn-outline::before {
  content: '';
  position: absolute;
  inset: 0;
  background: var(--primary);
  transform: scaleX(0);
  transform-origin: left;
  transition: transform 0.35s ease;
  z-index: -1;
}

.btn-outline:hover {
  color: #fff;
  transform: scale(1.05);
  box-shadow: 0 8px 20px rgba(30, 42, 94, 0.2);
}

.btn-outline:hover::before {
  transform: scaleX(1);
}

/* Cards 3D lift */
.card-lift {
  transition: transform 0.35s ease, box-shadow 0.35s ease;
}

.card-lift:hover {
  transform: translateY(-10px);
  box-shadow: 0 20px 40px rgba(30, 42, 94, 0.12);
}

.card-lift:hover .card-icon {
  animation: icon-bounce 0.6s ease;
}

@keyframes icon-bounce {
  0%, 100% { transform: rotate(0deg) scale(1); }
  25% { transform: rotate(-8deg) scale(1.1); }
  75% { transform: rotate(8deg) scale(1.1); }
}

/* Parallax layers */
.parallax-wrap {
  position: relative;
  overflow: hidden;
}

.parallax-bg {
  will-change: transform;
}

/* Stats gold numbers */
.stat-number {
  color: var(--accent);
  font-weight: 800;
  font-size: clamp(1.75rem, 4vw, 2.5rem);
  line-height: 1.2;
}

/* Demo animation samples */
.demo-btn-pulse {
  animation: pulse-ring 2s ease infinite;
}

@keyframes pulse-ring {
  0% { box-shadow: 0 0 0 0 rgba(255, 107, 74, 0.5); }
  70% { box-shadow: 0 0 0 12px rgba(255, 107, 74, 0); }
  100% { box-shadow: 0 0 0 0 rgba(255, 107, 74, 0); }
}

.demo-fade-text {
  animation: fade-blur 3s ease-in-out infinite alternate;
}

@keyframes fade-blur {
  0% { opacity: 0.4; filter: blur(4px); }
  100% { opacity: 1; filter: blur(0); }
}

.demo-disk-nav span {
  display: block;
  width: 8px;
  height: 8px;
  border-radius: 50%;
  background: var(--secondary);
  animation: disk-orbit 4s linear infinite;
}

@keyframes disk-orbit {
  0% { transform: rotate(0deg) translateX(24px) rotate(0deg); }
  100% { transform: rotate(360deg) translateX(24px) rotate(-360deg); }
}

/* Device mockup */
.device-macbook {
  background: #1a1a1a;
  border-radius: 12px 12px 4px 4px;
  padding: 12px 12px 24px;
  box-shadow: 0 25px 50px rgba(0, 0, 0, 0.2);
}

.device-macbook::after {
  content: '';
  display: block;
  width: 60px;
  height: 6px;
  margin: 8px auto 0;
  background: #333;
  border-radius: 0 0 4px 4px;
}

.device-phone {
  width: 140px;
  background: #111;
  border-radius: 24px;
  padding: 10px;
  box-shadow: 0 15px 35px rgba(0, 0, 0, 0.25);
}

.device-phone .screen {
  border-radius: 16px;
  overflow: hidden;
}

/* Testimonial carousel */
.testimonial-track {
  display: flex;
  transition: transform 0.5s ease;
}

/* Accordion */
.accordion-content {
  max-height: 0;
  overflow: hidden;
  transition: max-height 0.4s ease, padding 0.3s ease;
}

.accordion-item.is-open .accordion-content {
  max-height: 800px;
}

.accordion-item.is-open .accordion-icon {
  transform: rotate(180deg);
}

/* Nav active */
.nav-link.active {
  color: var(--secondary);
  font-weight: 700;
}

.nav-link.active::after {
  content: '';
  position: absolute;
  bottom: -4px;
  left: 0;
  right: 0;
  height: 2px;
  background: var(--secondary);
  border-radius: 2px;
}

/* Mobile menu */
.mobile-menu {
  transform: translateX(100%);
  transition: transform 0.35s ease;
}

.mobile-menu.is-open {
  transform: translateX(0);
}

/* Page transition */
#page-content {
  animation: page-in 0.4s ease;
}

@keyframes page-in {
  from { opacity: 0; transform: translateY(12px); }
  to { opacity: 1; transform: translateY(0); }
}

/* Tab panels */
.tab-panel {
  display: none;
}

.tab-panel.is-active {
  display: block;
  animation: page-in 0.35s ease;
}

.tab-btn.is-active {
  background: var(--primary);
  color: #fff;
}

