export const ROUTES = [
  { path: '/', id: 'home', label: 'Home', nav: false },
  { path: '/service', id: 'service', label: 'Service' },
  { path: '/price', id: 'price', label: 'Price' },
  { path: '/works', id: 'works', label: 'Works' },
  { path: '/faq', id: 'faq', label: 'FAQ' },
  { path: '/company', id: 'company', label: 'Company' },
  { path: '/contact', id: 'contact', label: 'Contact' },
];

import { ROUTES } from './data.js';
import { PAGE_RENDERERS } from './pages.js';

const contentEl = () => document.getElementById('page-content');

export function getRouteFromPath(pathname) {
  const path = pathname.replace(/\/index\.html$/, '').replace(/\/$/, '') || '/';
  const route = ROUTES.find((r) => r.path === path || (path === '' && r.path === '/'));
  return route || ROUTES[0];
}

export function navigate(path, push = true) {
  const normalized = path.startsWith('/') ? path : `/${path}`;
  const route = getRouteFromPath(normalized);

  if (push) {
    history.pushState({ routeId: route.id }, '', normalized === '/' ? '/' : normalized);
  }

  renderPage(route.id);
  updateActiveNav(route.path);
  window.scrollTo({ top: 0, behavior: 'smooth' });
  document.title = `CODING ALIVE | ${route.label === 'Home' ? 'コーディング代行' : route.label}`;
}

function renderPage(id) {
  const el = contentEl();
  const render = PAGE_RENDERERS[id];
  if (!render || !el) return;
  el.innerHTML = render();
  window.dispatchEvent(new CustomEvent('page:rendered', { detail: { id } }));
}

function updateActiveNav(path) {
  document.querySelectorAll('[data-nav]').forEach((link) => {
    const href = link.getAttribute('href');
    const isHome = path === '/' && (href === '/' || href === '/index.html');
    const isMatch = href === path || (path === '/' && href === '/');
    link.classList.toggle('active', isMatch || isHome);
  });
}

export function initRouter() {
  document.addEventListener('click', (e) => {
    const link = e.target.closest('[data-nav]');
    if (!link) return;
    const href = link.getAttribute('href');
    if (!href || href.startsWith('http') || href.startsWith('#')) return;
    e.preventDefault();
    navigate(href);
  });

  window.addEventListener('popstate', () => {
    const route = getRouteFromPath(location.pathname);
    history.replaceState({ routeId: route.id }, '', location.pathname);
    renderPage(route.id);
    updateActiveNav(route.path);
    window.dispatchEvent(new CustomEvent('page:rendered', { detail: { id: route.id } }));
  });

  const route = getRouteFromPath(location.pathname);
  history.replaceState({ routeId: route.id }, '', location.pathname);
  renderPage(route.id);
  updateActiveNav(route.path);
}

import { SITE } from './data.js';
import { initRouter } from './router.js';

function initMobileMenu() {
  const toggle = document.getElementById('menu-toggle');
  const menu = document.getElementById('mobile-menu');
  const close = document.getElementById('menu-close');
  if (!toggle || !menu) return;

  const open = () => menu.classList.add('is-open');
  const shut = () => menu.classList.remove('is-open');

  toggle.addEventListener('click', open);
  close?.addEventListener('click', shut);
  menu.querySelectorAll('[data-nav]').forEach((l) => l.addEventListener('click', shut));
}

function initLogoGlitch() {
  const logo = document.getElementById('site-logo');
  if (!logo) return;
  logo.classList.add('glitch-once');
  setTimeout(() => logo.classList.remove('glitch-once'), 500);
}

function initScrollReveal() {
  const observer = new IntersectionObserver(
    (entries) => {
      entries.forEach((entry) => {
        if (entry.isIntersecting) {
          entry.target.classList.add('is-visible');
          observer.unobserve(entry.target);
        }
      });
    },
    { threshold: 0.12, rootMargin: '0px 0px -40px 0px' }
  );

  document.querySelectorAll('.reveal, .reveal-stagger, .hero-underline').forEach((el) => {
    observer.observe(el);
  });
}

function initParallax() {
  const layers = document.querySelectorAll('[data-parallax]');
  if (!layers.length) return;

  const onScroll = () => {
    layers.forEach((layer) => {
      const speed = parseFloat(layer.dataset.parallax) || 0.2;
      const rect = layer.closest('.parallax-wrap')?.getBoundingClientRect();
      if (!rect) return;
      const offset = (window.innerHeight - rect.top) * speed * 0.1;
      layer.style.transform = `translateY(${offset}px)`;
    });
  };

  window.addEventListener('scroll', onScroll, { passive: true });
  onScroll();
}

function initAccordions(root = document) {
  root.querySelectorAll('[data-accordion]').forEach((item) => {
    const trigger = item.querySelector('.accordion-trigger');
    if (!trigger || trigger.dataset.bound) return;
    trigger.dataset.bound = '1';
    trigger.addEventListener('click', () => {
      const wasOpen = item.classList.contains('is-open');
      root.querySelectorAll('[data-accordion]').forEach((i) => i.classList.remove('is-open'));
      if (!wasOpen) item.classList.add('is-open');
    });
  });
}

function initPriceTabs(root = document) {
  const container = root.getElementById('price-tabs');
  if (!container) return;

  container.querySelectorAll('.tab-btn').forEach((btn) => {
    btn.addEventListener('click', () => {
      const tab = btn.dataset.tab;
      container.querySelectorAll('.tab-btn').forEach((b) => b.classList.remove('is-active'));
      btn.classList.add('is-active');
      root.querySelectorAll('.tab-panel').forEach((p) => p.classList.remove('is-active'));
      root.getElementById(`tab-${tab}`)?.classList.add('is-active');
    });
  });
}

function initContactForm(root = document) {
  const form = root.getElementById('contact-form');
  if (!form) return;

  const emailRe = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
  const phoneRe = /^[\d\-+()\s]{10,}$/;

  form.addEventListener('submit', (e) => {
    e.preventDefault();
    let valid = true;

    const fields = [
      { id: 'name', msg: 'お名前を入力してください' },
      { id: 'email', msg: '有効なメールアドレスを入力してください', test: (v) => emailRe.test(v) },
      { id: 'phone', msg: '有効な電話番号を入力してください', test: (v) => phoneRe.test(v) },
    ];

    fields.forEach(({ id, msg, test }) => {
      const input = form.querySelector(`#${id}`);
      const err = form.querySelector(`[data-error="${id}"]`);
      const value = input?.value.trim() || '';
      const ok = value && (!test || test(value));
      if (!ok) {
        valid = false;
        err.textContent = msg;
        err.classList.remove('hidden');
        input?.classList.add('border-red-400');
      } else {
        err.classList.add('hidden');
        input?.classList.remove('border-red-400');
      }
    });

    if (valid) {
      form.querySelector('#form-success')?.classList.remove('hidden');
      form.reset();
    }
  });
}

let testimonialIndex = 0;
let testimonialTimer;

function buildTestimonialSlide(t) {
  return `
    <div class="min-w-full px-4 py-8">
      <div class="bg-white rounded-2xl shadow-xl p-8 md:p-12 max-w-3xl mx-auto border border-gray-100">
        <p class="text-sm font-bold text-[#FF6B4A] mb-2">${t.company}</p>
        <h3 class="text-xl font-bold text-[#1E2A5E] mb-4">${t.headline}</h3>
        <p class="text-gray-600 text-sm leading-relaxed line-clamp-6">${t.body}</p>
      </div>
    </div>`;
}

function initTestimonials(root = document) {
  const track = root.getElementById('testimonial-track');
  const dots = root.getElementById('testimonial-dots');
  if (!track || !dots) return;

  clearInterval(testimonialTimer);
  testimonialIndex = 0;

  track.innerHTML = SITE.testimonials.map(buildTestimonialSlide).join('');
  dots.innerHTML = SITE.testimonials
    .map(
      (_, i) =>
        `<button type="button" class="w-2.5 h-2.5 rounded-full transition ${i === 0 ? 'bg-[#FF6B4A]' : 'bg-gray-300'}" data-dot="${i}" aria-label="Slide ${i + 1}"></button>`
    )
    .join('');

  const go = (i) => {
    testimonialIndex = (i + SITE.testimonials.length) % SITE.testimonials.length;
    track.style.transform = `translateX(-${testimonialIndex * 100}%)`;
    dots.querySelectorAll('[data-dot]').forEach((d, j) => {
      d.classList.toggle('bg-[#FF6B4A]', j === testimonialIndex);
      d.classList.toggle('bg-gray-300', j !== testimonialIndex);
    });
  };

  dots.querySelectorAll('[data-dot]').forEach((d) => {
    d.addEventListener('click', () => go(parseInt(d.dataset.dot, 10)));
  });

  testimonialTimer = setInterval(() => go(testimonialIndex + 1), 6000);
}

function onPageRendered() {
  initScrollReveal();
  initParallax();
  initAccordions();
  initPriceTabs();
  initContactForm();
  initTestimonials();
}

document.addEventListener('DOMContentLoaded', () => {
  initRouter();
  initMobileMenu();
  initLogoGlitch();
  window.addEventListener('page:rendered', onPageRendered);
  onPageRendered();
});

